    state: &mut LuaState,
    panicf: Option<fn(&mut LuaState) -> Result<usize, LuaError>>,
) -> Option<fn(&mut LuaState) -> Result<usize, LuaError>> {
    // C: old = G(L)->panic; G(L)->panic = panicf; return old;
    let old = state.global_mut().panic;
    state.global_mut().panic = panicf;
