2049	                None
2050	            }
2051	        }
2052	        // C: case LUA_VLCF: return NULL;
2053	        LuaValue::Function(LuaClosure::LightC(_)) => None,
2054	        _ => {
2055	            debug_assert!(false, "function expected");
2056	            None
2057	        }
